import { useEffect, useState } from "react";
import { api, getAuthToken } from "../api";

export default function Home() {
  const [stats, setStats] = useState({ shops: 0, medicines: 0 });

  useEffect(() => {
    const loadStats = async () => {
      if (!getAuthToken()) {
        return;
      }

      try {
        const [shopsRes, medicinesRes] = await Promise.all([
          api.get("/shops/"),
          api.get("/medicines/"),
        ]);
        setStats({ shops: shopsRes.data.length, medicines: medicinesRes.data.length });
      } catch (err) {
        // Keep default stats if backend is unavailable.
      }
    };

    loadStats();
  }, []);

  return (
    <div className="page">
      <h1>Welcome to MedCompare</h1>
      <p>Search and compare medicine prices across nearby shops.</p>
      <div className="card">
        <p>Registered Shops: {stats.shops}</p>
        <p>Listed Medicines: {stats.medicines}</p>
      </div>
    </div>
  );
}
